import { useMutation, useQueryClient } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import { useTranslation } from "react-i18next";
import { Ingredient, RecipeStep, RecipeDifficulty } from "@/components/community/recipe/RecipeTypes";

interface EditRecipeParams {
  id: string;
  recipe_name: string;
  cook_time: number;
  difficulty: RecipeDifficulty;
  servings: number;
  ingredients: Ingredient[];
  steps: RecipeStep[];
  cover_image?: string | null;
  introduction?: string;
  nutrition?: {
    calories?: number;
    protein?: number;
    carbs?: number;
    fat?: number;
  };
  recipe_tags?: string[];
  recipe_category?: string;
}

export const useEditRecipe = () => {
  const queryClient = useQueryClient();
  const { t } = useTranslation();

  return useMutation({
    mutationFn: async (params: EditRecipeParams) => {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Not authenticated");

      const content = params.introduction || "";

      // Prepare image_urls
      const imageUrls: string[] = [];
      if (params.cover_image) {
        imageUrls.push(params.cover_image);
      }
      params.steps.forEach(step => {
        if (step.image_urls && step.image_urls.length > 0) {
          step.image_urls.forEach(url => imageUrls.push(url));
        } else if (step.image_url) {
          imageUrls.push(step.image_url);
        }
      });

      const { data, error } = await supabase
        .from("community_posts")
        .update({
          content,
          image_urls: imageUrls,
          recipe_name: params.recipe_name,
          cook_time: params.cook_time,
          difficulty: params.difficulty,
          servings: params.servings,
          ingredients: params.ingredients as unknown as any,
          steps: params.steps as unknown as any,
          nutrition: params.nutrition ? (params.nutrition as unknown as any) : null,
          recipe_tags: params.recipe_tags || null,
          recipe_category: params.recipe_category || null,
          status: "pending",
          moderation_status: "pending",
          risk_score: null,
          risk_reasons: null,
          ai_reviewed_at: null,
        } as any)
        .eq("id", params.id)
        .eq("author_id", user.id)
        .select()
        .single();

      if (error) throw error;

      // Trigger re-moderation
      try {
        await supabase.functions.invoke("moderate-post", {
          body: {
            post_id: data.id,
            content,
            user_id: user.id,
            image_urls: imageUrls,
          },
        });
      } catch (err) {
        console.error("Moderation call failed:", err);
      }

      return data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["community-posts"] });
      queryClient.invalidateQueries({ queryKey: ["community-post"] });
      queryClient.invalidateQueries({ queryKey: ["admin-community-posts"] });
      queryClient.invalidateQueries({ queryKey: ["has-posted-today"] });
      toast.success(t("recipe.editSuccess", "食谱已更新，等待审核"));
    },
    onError: (error) => {
      console.error("Edit recipe error:", error);
      toast.error(t("recipe.editError", "编辑失败"));
    },
  });
};
