import { useState, useRef, useEffect } from "react";
import { useTranslation } from "react-i18next";
import { Image, Video, X, Loader2, Calendar, MapPin, ArrowLeft, BookOpen } from "lucide-react";
import MultiRestaurantSelectDrawer from "./MultiRestaurantSelectDrawer";
import ActivitySelectDrawer from "./ActivitySelectDrawer";
import EmojiPicker from "./EmojiPicker";
import {
  Sheet,
  SheetContent,
  SheetTitle,
} from "@/components/ui/sheet";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { supabase } from "@/integrations/supabase/client";
import { useEditPost, CommunityPost } from "@/hooks/useCommunityPosts";
import { useActivities } from "@/hooks/useActivities";

import { useUserRole } from "@/hooks/useUserRole";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { toast } from "sonner";
import * as VisuallyHidden from "@radix-ui/react-visually-hidden";

interface EditPostDialogProps {
  post: CommunityPost;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

const EditPostDialog = ({ post, open, onOpenChange }: EditPostDialogProps) => {
  const { t } = useTranslation();
  const { getLocalizedField } = useLocalizedContent();
  const editPost = useEditPost();
  const { data: activities } = useActivities();
  
  const { isMerchant, isAdmin, isSupervisor } = useUserRole();
  const isRegularUser = !isMerchant && !isSupervisor && !isAdmin;

  const [content, setContent] = useState(post.content);
  const [imageUrls, setImageUrls] = useState<string[]>(post.image_urls || []);
  const [videoUrl, setVideoUrl] = useState<string | null>(post.video_url || null);
  const [activityId, setActivityId] = useState<string>(post.activity_id || "");
  const [restaurantIds, setRestaurantIds] = useState<string[]>(
    post.restaurants?.map(r => r.id) || (post.restaurant ? [post.restaurant.id] : [])
  );
  const [uploading, setUploading] = useState(false);
  const [restaurantOpen, setRestaurantOpen] = useState(false);
  const [activityOpen, setActivityOpen] = useState(false);
  const [showRestaurantError, setShowRestaurantError] = useState(false);
  const [generatingNeijing, setGeneratingNeijing] = useState(false);

  const imageInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);

  const activeActivities = activities?.filter((a) => a.status === "published") || [];

  // Reset form when post changes
  useEffect(() => {
    if (open) {
      setContent(post.content);
      setImageUrls(post.image_urls || []);
      setVideoUrl(post.video_url || null);
      setActivityId(post.activity_id || "");
      setRestaurantIds(
        post.restaurants?.map(r => r.id) || (post.restaurant ? [post.restaurant.id] : [])
      );
    }
  }, [open, post]);

  const getMerchantRestaurantName = () => {
    const merchantRestaurant = post.restaurant;
    if (!merchantRestaurant) return t("community.noRestaurant", "未关联餐厅");
    return getLocalizedField(merchantRestaurant, "name");
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    if (imageUrls.length + files.length > 9) {
      toast.error(t("community.maxImages", "最多上传9张图片"));
      return;
    }
    setUploading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Not authenticated");
      const uploadedUrls: string[] = [];
      for (const file of Array.from(files)) {
        const fileExt = file.name.split(".").pop();
        const fileName = `${user.id}/${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`;
        const { error: uploadError } = await supabase.storage.from("community-posts").upload(fileName, file);
        if (uploadError) throw uploadError;
        const { data: { publicUrl } } = supabase.storage.from("community-posts").getPublicUrl(fileName);
        uploadedUrls.push(publicUrl);
      }
      setImageUrls((prev) => [...prev, ...uploadedUrls]);
    } catch (error) {
      console.error("Upload error:", error);
      toast.error(t("common.uploadError", "上传失败"));
    } finally {
      setUploading(false);
      if (imageInputRef.current) imageInputRef.current.value = "";
    }
  };

  const handleVideoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (file.size > 100 * 1024 * 1024) {
      toast.error(t("community.videoTooLarge", "视频不能超过100MB"));
      return;
    }
    setUploading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Not authenticated");
      const videoExt = file.name.split(".").pop();
      const videoFileName = `${user.id}/${Date.now()}.${videoExt}`;
      const { error: videoError } = await supabase.storage.from("community-posts").upload(videoFileName, file);
      if (videoError) throw videoError;
      const { data: { publicUrl: videoPublicUrl } } = supabase.storage.from("community-posts").getPublicUrl(videoFileName);
      setVideoUrl(videoPublicUrl);
    } catch (error) {
      console.error("Upload error:", error);
      toast.error(t("common.uploadError", "上传失败"));
    } finally {
      setUploading(false);
      if (videoInputRef.current) videoInputRef.current.value = "";
    }
  };

  const removeImage = (index: number) => setImageUrls((prev) => prev.filter((_, i) => i !== index));
  const removeVideo = () => setVideoUrl(null);

  const handleGenerateNeijing = async () => {
    if (!content.trim()) {
      toast.error(t("community.contentRequired", "请先输入内容"));
      return;
    }
    setGeneratingNeijing(true);
    try {
      const { data, error } = await supabase.functions.invoke("generate-post-neijing", {
        body: { content: content.trim() },
      });
      if (error) throw error;
      if (data?.neijing_text) {
        setContent((prev) => prev + "\n\n---\n☯ " + t("community.neijingTitle", "东方智慧·易经解读") + "\n" + data.neijing_text);
        toast.success(t("community.neijingGenerated", "易经解读已生成"));
      } else if (data?.error) {
        toast.error(data.error);
      }
    } catch (err: any) {
      console.error("Generate neijing error:", err);
      toast.error(t("community.neijingError", "生成失败，请稍后再试"));
    } finally {
      setGeneratingNeijing(false);
    }
  };

  const handleSubmit = async () => {
    setShowRestaurantError(false);
    if (!content.trim()) {
      toast.error(t("community.contentRequired", "请输入内容"));
      return;
    }
    if (isRegularUser && restaurantIds.length === 0) {
      setShowRestaurantError(true);
      toast.error(t("community.restaurantRequired", "请选择餐厅"));
      return;
    }

    await editPost.mutateAsync({
      id: post.id,
      content,
      image_urls: imageUrls,
      video_url: videoUrl,
      activity_id: activityId || null,
      restaurant_ids: restaurantIds.length > 0 ? restaurantIds : undefined,
    });

    onOpenChange(false);
  };

  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent
        side="bottom"
        className="h-full flex flex-col p-0 rounded-none border-0 [&>button]:hidden"
      >
        <VisuallyHidden.Root>
          <SheetTitle>{t("community.editPost", "编辑帖子")}</SheetTitle>
        </VisuallyHidden.Root>

        <input ref={imageInputRef} type="file" accept="image/*" multiple className="hidden" onChange={handleImageUpload} />
        <input ref={videoInputRef} type="file" accept="video/*" className="hidden" onChange={handleVideoUpload} />

        {/* Header */}
        <div className="border-b bg-background shrink-0">
          <div className="container mx-auto max-w-2xl lg:max-w-4xl flex items-center justify-between px-4 py-3">
            <button
              type="button"
              onClick={() => onOpenChange(false)}
              className="p-1 -ml-1 hover:bg-muted rounded-md transition-colors"
            >
              <ArrowLeft className="h-5 w-5" />
            </button>
            <span className="font-medium text-sm">{t("community.editPost", "编辑帖子")}</span>
            <Button
              size="sm"
              onClick={handleSubmit}
              disabled={editPost.isPending || !content.trim()}
              className="rounded-full px-6"
            >
              {editPost.isPending && <Loader2 className="h-4 w-4 mr-2 animate-spin" />}
              {t("community.resubmit", "重新提交")}
            </Button>
          </div>
        </div>

        {/* Edit notice */}
        <div className="border-b border-amber-500/30 bg-amber-500/10 shrink-0">
          <div className="container mx-auto max-w-2xl lg:max-w-4xl px-4 py-2 text-sm text-amber-700 dark:text-amber-400">
            {t("community.editNotice", "编辑后帖子将重新提交审核")}
          </div>
        </div>

        {/* Main content - scrollable */}
        <div className="flex-1 overflow-y-auto">
          <div className="container mx-auto max-w-2xl lg:max-w-4xl px-4">
            {/* Text area */}
            <div className="py-4">
              <Textarea
                value={content}
                onChange={(e) => setContent(e.target.value)}
                placeholder={t("community.contentPlaceholder", "分享你的想法...")}
                className="min-h-[200px] lg:min-h-[300px] border-none shadow-none resize-none focus-visible:ring-0 p-0 text-base whitespace-pre-wrap"
                autoFocus
              />
            </div>

            {/* Media preview */}
            {(imageUrls.length > 0 || videoUrl) && (
              <div className="pb-4">
                {imageUrls.length > 0 && (
                  <div className={`grid gap-2 mb-3 ${imageUrls.length === 1 ? "grid-cols-1 max-w-xs" : imageUrls.length <= 4 ? "grid-cols-2 max-w-md" : "grid-cols-3 max-w-lg"}`}>
                    {imageUrls.map((url, index) => (
                      <div key={index} className="relative aspect-square rounded-lg overflow-hidden bg-muted group">
                        <img src={url} alt="" className="w-full h-full object-cover" />
                        <button
                          type="button"
                          onClick={() => removeImage(index)}
                          className="absolute top-1.5 right-1.5 p-1 bg-black/60 rounded-full text-white opacity-0 group-hover:opacity-100 hover:bg-black/80 transition-opacity"
                        >
                          <X className="h-3.5 w-3.5" />
                        </button>
                      </div>
                    ))}
                  </div>
                )}
                {videoUrl && (
                  <div className="relative rounded-lg overflow-hidden bg-black group max-w-md">
                    <video src={videoUrl} controls className="w-full max-h-[280px]" preload="metadata" />
                    <button
                      type="button"
                      onClick={removeVideo}
                      className="absolute top-2 right-2 p-1 bg-black/60 rounded-full text-white opacity-0 group-hover:opacity-100 hover:bg-black/80 transition-opacity"
                    >
                      <X className="h-4 w-4" />
                    </button>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>

        {/* Bottom toolbar - sticky */}
        <div className="border-t bg-background shrink-0">
          <div className="container mx-auto max-w-2xl lg:max-w-4xl px-4 py-2.5 pb-[max(0.625rem,env(safe-area-inset-bottom))]">
            <div className="flex items-center gap-1 flex-wrap">
              {/* Media buttons */}
              <button
                type="button"
                onClick={() => imageInputRef.current?.click()}
                disabled={uploading || imageUrls.length >= 9}
                className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-muted-foreground hover:text-foreground hover:bg-muted disabled:opacity-40 transition-colors"
              >
                <Image className="h-5 w-5" />
                <span className="text-sm">{t("community.photo", "照片")}</span>
              </button>
              <button
                type="button"
                onClick={() => videoInputRef.current?.click()}
                disabled={uploading || !!videoUrl}
                className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-muted-foreground hover:text-foreground hover:bg-muted disabled:opacity-40 transition-colors"
              >
                <Video className="h-5 w-5" />
                <span className="text-sm">{t("community.video", "视频")}</span>
              </button>

              <div className="w-px h-5 bg-border mx-1" />

              <EmojiPicker onSelect={(emoji) => setContent((prev) => prev + emoji)} />

              <div className="w-px h-5 bg-border mx-1" />

              {/* Restaurant */}
              <div className={`flex items-center gap-2 px-2 py-1 rounded-lg ${showRestaurantError && isRegularUser && restaurantIds.length === 0 ? "text-destructive" : ""}`}>
                <MapPin className={`h-4 w-4 shrink-0 ${showRestaurantError && isRegularUser && restaurantIds.length === 0 ? "text-destructive" : "text-muted-foreground"}`} />
                {isMerchant ? (
                  <span className="text-sm text-muted-foreground truncate">{getMerchantRestaurantName()}</span>
                ) : (
                  <MultiRestaurantSelectDrawer
                    open={restaurantOpen}
                    onOpenChange={(open) => { setRestaurantOpen(open); if (open) setShowRestaurantError(false); }}
                    value={restaurantIds}
                    onSelect={(ids) => { setRestaurantIds(ids); setShowRestaurantError(false); }}
                    
                    required={isRegularUser}
                  />
                )}
              </div>

              <div className="w-px h-5 bg-border mx-1" />

              {/* Activity */}
              <div className="flex items-center gap-2 px-2 py-1">
                <Calendar className="h-4 w-4 text-muted-foreground shrink-0" />
                <ActivitySelectDrawer
                  open={activityOpen}
                  onOpenChange={setActivityOpen}
                  value={activityId}
                  onSelect={setActivityId}
                  activities={activeActivities}
                />
              </div>

              <div className="w-px h-5 bg-border mx-1" />

              {/* I Ching / Neijing */}
              <button
                type="button"
                onClick={handleGenerateNeijing}
                disabled={generatingNeijing || !content.trim()}
                className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-muted-foreground hover:text-foreground hover:bg-muted disabled:opacity-40 transition-colors"
              >
                {generatingNeijing ? <Loader2 className="h-5 w-5 animate-spin" /> : <BookOpen className="h-5 w-5" />}
                <span className="text-sm">{t("community.neijingButton", "易经")}</span>
              </button>

              {uploading && <Loader2 className="h-4 w-4 animate-spin ml-auto text-muted-foreground" />}
            </div>
            {showRestaurantError && isRegularUser && restaurantIds.length === 0 && (
              <p className="text-xs text-destructive mt-1">{t("community.restaurantRequired", "请选择餐厅")}</p>
            )}
          </div>
        </div>
      </SheetContent>
    </Sheet>
  );
};

export default EditPostDialog;
